import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import LoginScreen from './components/LoginScreen';
import StudentDashboard from './components/StudentDashboard';
import AccountantDashboard from './components/AccountantDashboard';
import DebtDetails from './components/DebtDetails';
import QRPayment from './components/QRPayment';
import PaymentReceipt from './components/PaymentReceipt';
import PaymentHistory from './components/PaymentHistory';
import Sidebar from './components/Sidebar';
import DebugMode from './components/DebugMode';
import RoadmapModal from './components/RoadmapModal';
import TraceabilityMatrix from './components/TraceabilityMatrix';
import ExtensionRequest from './components/ExtensionRequest';
import ReminderSettings from './components/ReminderSettings';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState('STUDENT');
  const [currentScreen, setCurrentScreen] = useState('dashboard');
  const [showRoadmapModal, setShowRoadmapModal] = useState(false);

  const handleLogin = (role) => {
    setIsAuthenticated(true);
    setUserRole(role);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentScreen('dashboard');
  };

  const handleNavigation = (screen) => {
    setCurrentScreen(screen);
  };

  if (!isAuthenticated) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <Router>
      <div className="flex h-screen bg-gray-50">
        <Sidebar 
          userRole={userRole}
          currentScreen={currentScreen}
          onNavigate={handleNavigation}
          onLogout={handleLogout}
          onShowRoadmap={() => setShowRoadmapModal(true)}
        />
        
        <main className="flex-1 overflow-y-auto">
          <DebugMode />
          
          {userRole === 'STUDENT' ? (
            <Routes>
              <Route path="/" element={<Navigate to="/dashboard" replace />} />
              <Route path="/dashboard" element={<StudentDashboard onNavigate={handleNavigation} />} />
              <Route path="/debt-details" element={<DebtDetails onNavigate={handleNavigation} />} />
              <Route path="/qr-payment" element={<QRPayment onNavigate={handleNavigation} />} />
              <Route path="/payment-receipt" element={<PaymentReceipt onNavigate={handleNavigation} />} />
              <Route path="/payment-history" element={<PaymentHistory onNavigate={handleNavigation} />} />
              <Route path="/extension-request" element={<ExtensionRequest />} />
            </Routes>
          ) : (
            <Routes>
              <Route path="/" element={<Navigate to="/dashboard" replace />} />
              <Route path="/dashboard" element={<AccountantDashboard />} />
              <Route path="/traceability-matrix" element={<TraceabilityMatrix />} />
              <Route path="/reminder-settings" element={<ReminderSettings />} />
              <Route path="/extension-request" element={<ExtensionRequest />} />
            </Routes>
          )}
        </main>
        
        <RoadmapModal 
          isOpen={showRoadmapModal}
          onClose={() => setShowRoadmapModal(false)}
        />
      </div>
    </Router>
  );
}

export default App;
